-- ============================================
-- Legislacao full-site: delegado-eder-mauro / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/178908
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = delegado-eder-mauro-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 46
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=178908, tipo Deputado(a), ordemAssinatura=1.
-- 54 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'delegado-eder-mauro';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'delegado-eder-mauro: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao delegado-eder-mauro: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2584825', '2566572', '2566562', '2556941', '2551860', '2551853', '2530997', '2506328', '2566571', '2556940', '2551859', '2551851', '2530617', '2506215', '2581192', '2566569', '2562133', '2556955', '2556937', '2551918', '2551857', '2551850', '2531700', '2527886', '2506209', '2567059', '2566566', '2562096', '2556945', '2556912', '2551886', '2551856', '2551849', '2531589', '2506201', '2566947', '2566573', '2566564', '2561986', '2556942', '2556893', '2551864', '2551855', '2506330', '2505440', '2600792');
  IF target_present <> 46 THEN
    RAISE EXCEPTION 'Pre-condicao delegado-eder-mauro: esperadas 46 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2584825', '2566572', '2566562', '2556941', '2551860', '2551853', '2530997', '2506328', '2566571', '2556940', '2551859', '2551851', '2530617', '2506215', '2581192', '2566569', '2562133', '2556955', '2556937', '2551918', '2551857', '2551850', '2531700', '2527886', '2506209', '2567059', '2566566', '2562096', '2556945', '2556912', '2551886', '2551856', '2551849', '2531589', '2506201', '2566947', '2566573', '2566564', '2561986', '2556942', '2556893', '2551864', '2551855', '2506330', '2505440', '2600792')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'delegado-eder-mauro-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao delegado-eder-mauro: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao delegado-eder-mauro: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

